""""
sync_transcripts.py — Utility to backup/synchronize all local Gemini agent conversation logs
from the hidden AppData folder to the project's docs/system_generated_logs folder.
"""

from __future__ import annotations

import os
import shutil
from pathlib import Path

BRAIN_DIR = Path(r"C:\Users\thoma\.gemini\antigravity\brain")
DST_PATHS = [
    Path(r"C:\skill-suggester\docs\system_generated_logs"),
    Path(r"Y:\greenstories\TomOnly\skill-suggester\docs\system_generated_logs")
]

def sync_all():
    if not BRAIN_DIR.exists():
        print(f"[Sync] Error: Brain directory not found at {BRAIN_DIR}")
        return

    for dst in DST_PATHS:
        dst.mkdir(parents=True, exist_ok=True)

    copied_count = 0
    for item in BRAIN_DIR.iterdir():
        if not item.is_dir() or item.name == "tempmediaStorage":
            continue

        src_log = item / ".system_generated" / "logs" / "transcript.jsonl"
        if src_log.exists():
            for dst in DST_PATHS:
                dest_file = dst / f"{item.name}_transcript.jsonl"
                # Copy or update only if size/mtime differs
                if not dest_file.exists() or src_log.stat().st_size != dest_file.stat().st_size:
                    try:
                        shutil.copy2(src_log, dest_file)
                        copied_count += 1
                    except Exception as e:
                        print(f"[Sync] Warning: Failed to copy {item.name}: {e}")

    print(f"[Sync] Synchronized transcripts: updated/copied {copied_count} files.")

if __name__ == "__main__":
    sync_all()
"
